// DJ OPUS - EPIC TRANCE SET
// Section 3: THE DROP - Full Euphoria
setcps(138/60/4)

// === YOUR SLIDERS ===
let masterVol = slider(0.8, 0, 1, 0.01, "MASTER Volume")
let choirVol = slider(0.8, 0, 0.8, 0.01, "DIVA CHOIR")
let leadVol = slider(0.5, 0, 0.8, 0.01, "SUPERSAW Lead")
let filterOpen = slider(4000, 500, 12000, 10, "FILTER Open")
let stereoWidth = slider(0.5, 0, 1, 0.01, "STEREO Width")
let energy = slider(0.7, 0, 1, 0.01, "ENERGY Level")

// KICK - full power four on the floor
let kick = s("bd").bank("RolandTR909")
  .gain(1.2)
  .struct("x x x x")

// CLAP on 2 and 4
let clap = s("cp").bank("RolandTR909")
  .gain(0.8)
  .struct("~ x ~ x")
  .room(0.25)

// OFFBEAT HATS - driving
let hats = s("hh").bank("RolandTR909")
  .gain(energy.mul(0.6))
  .struct("~ x ~ x ~ x ~ x")
  .cutoff(filterOpen)

// OPEN HAT accents
let oh = s("oh").bank("RolandTR909")
  .gain(0.4)
  .struct("~ ~ ~ ~ ~ ~ x ~")

// SUPERSAW BASS - fat rolling line
let bass = note("<a2 a2 e2 e2 f2 f2 d2 d2>")
  .s("sawtooth")
  .superimpose(x => x.add(0.08))
  .cutoff(sine.range(400, 2200).slow(4))
  .resonance(14)
  .decay(0.2)
  .sustain(0.08)
  .gain(energy.mul(0.7))
  .struct("x ~ x x ~ x x ~")

// DIVA CHOIR - the moment
let choir = note("<[a3,e4,c5] [e3,b3,g4] [f3,c4,a4] [d3,a3,f4]>".slow(2))
  .s("gm_choir_aahs")
  .gain(choirVol)
  .cutoff(filterOpen)
  .room(0.85)
  .size(0.9)
  .vowel("<a e i o>".slow(4))

// SUPERSAW LEAD - euphoric melody
let lead = note("a4 ~ c5 e5 ~ a5 e5 c5")
  .s("sawtooth")
  .superimpose(x => x.add(0.1))
  .superimpose(x => x.add(-0.1))
  .cutoff(filterOpen)
  .resonance(6)
  .decay(0.3)
  .sustain(0.15)
  .gain(leadVol)
  .delay(0.4)
  .delaytime(3/16)
  .delayfeedback(0.45)
  .room(0.5)
  .jux(rev)

// TRANCE ARP - cascading
let arp = note("a4 c5 e5 a5 c6 a5 e5 c5")
  .s("triangle")
  .cutoff(filterOpen.mul(0.8))
  .resonance(12)
  .decay(0.1)
  .sustain(0)
  .gain(energy.mul(0.3))
  .delay(0.5)
  .delaytime(3/16)
  .delayfeedback(0.55)
  .room(0.4)

// PAD - wide atmospheric bed
let pad = note("<[a3,e4] [e3,b3] [f3,c4] [d3,a3]>".slow(2))
  .s("sawtooth")
  .superimpose(x => x.add(0.05))
  .cutoff(filterOpen.mul(0.6))
  .resonance(5)
  .attack(1.2)
  .decay(2)
  .sustain(0.5)
  .release(2)
  .gain(0.25)
  .room(0.9)
  .size(0.95)

// CRASH on beat 1 every 4 bars
let crash = s("oh").bank("RolandTR909")
  .speed(0.5)
  .gain(0.5)
  .room(0.8)
  .struct("x ~ ~ ~ ~ ~ ~ ~")
  .slow(4)

stack(kick, clap, hats, oh, bass, choir, lead, arp, pad, crash)
  .gain(masterVol)
